import type { Meta, StoryObj } from '@storybook/react-vite';
import { Text } from './Text';
import { Space } from '../Space';

const meta = {
  title: 'Components/Text',
  component: Text,
  tags: ['autodocs'],
  argTypes: {
    type: {
      control: 'select',
      options: ['primary', 'success', 'warning', 'danger', 'info'],
    },
    size: { control: 'inline-radio', options: ['large', 'default', 'small'] },
    truncated: { control: 'boolean' },
    lineClamp: { control: 'number' },
    tag: { control: false },
  },
  args: {
    children: 'The quick brown fox jumps over the lazy dog.',
  },
} satisfies Meta<typeof Text>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Playground: Story = {};

export const Types: Story = {
  render: () => (
    <Space direction="vertical" align="start">
      <Text>Default</Text>
      <Text type="primary">Primary</Text>
      <Text type="success">Success</Text>
      <Text type="warning">Warning</Text>
      <Text type="danger">Danger</Text>
      <Text type="info">Info</Text>
    </Space>
  ),
};

export const Sizes: Story = {
  render: () => (
    <Space direction="vertical" align="start">
      <Text size="large">Large text</Text>
      <Text>Default text</Text>
      <Text size="small">Small text</Text>
    </Space>
  ),
};

export const Truncated: Story = {
  render: () => (
    <div style={{ width: 240 }}>
      <Text truncated>
        This is a very long single line of text that will be truncated with an ellipsis.
      </Text>
    </div>
  ),
};

export const LineClamp: Story = {
  name: 'Line clamp',
  render: () => (
    <div style={{ width: 240 }}>
      <Text lineClamp={2}>
        This paragraph is clamped to two lines. Any content beyond the second line is hidden
        behind an ellipsis so the layout stays compact and predictable.
      </Text>
    </div>
  ),
};

import {
  type CSSProperties,
  createElement,
  type ElementType,
  forwardRef,
  type HTMLAttributes,
  type ReactNode,
} from 'react';
import { cls, useNamespace } from '../../utils';

export type TextType = 'primary' | 'success' | 'warning' | 'danger' | 'info';

export type TextSize = 'large' | 'default' | 'small';

export interface TextProps extends HTMLAttributes<HTMLElement> {
  /** Visual variant. */
  type?: TextType;
  /** Size. */
  size?: TextSize;
  /** Rendered host element. */
  tag?: ElementType;
  /** Truncate to a single line with an ellipsis. */
  truncated?: boolean;
  /** Clamp to a number of lines with an ellipsis. */
  lineClamp?: number | string;
  children?: ReactNode;
}

export const Text = forwardRef<HTMLElement, TextProps>(function Text(props, ref) {
  const {
    type,
    size = 'default',
    tag = 'span',
    truncated = false,
    lineClamp,
    className,
    style,
    children,
    ...rest
  } = props;

  const ns = useNamespace('text');
  const hasClamp = lineClamp !== undefined && lineClamp !== null;

  const classes = cls(
    ns.b(),
    type && ns.m(type),
    size !== 'default' && ns.m(size),
    ns.is('truncated', truncated && !hasClamp),
    ns.is('line-clamp', hasClamp),
    className,
  );

  const mergedStyle: CSSProperties = hasClamp
    ? { ...style, [ns.cssVar('line-clamp')]: String(lineClamp) }
    : (style as CSSProperties);

  return createElement(
    tag,
    { ref, className: classes, style: mergedStyle, ...rest },
    children,
  );
});

.ec-text {
  --ec-text-color: var(--ec-text-color-regular);
  --ec-text-font-size: var(--ec-font-size-base);
  --ec-text-line-clamp: 1;

  box-sizing: border-box;
  font-family: inherit;
  font-size: var(--ec-text-font-size);
  font-weight: var(--ec-font-weight-primary);
  line-height: 1.5;
  color: var(--ec-text-color);
}

/* ---- Type variants ---- */
.ec-text--primary {
  --ec-text-color: var(--ec-color-primary);
}

.ec-text--success {
  --ec-text-color: var(--ec-color-success);
}

.ec-text--warning {
  --ec-text-color: var(--ec-color-warning);
}

.ec-text--danger {
  --ec-text-color: var(--ec-color-danger);
}

.ec-text--info {
  --ec-text-color: var(--ec-color-info);
}

/* ---- Sizes ---- */
.ec-text--large {
  --ec-text-font-size: var(--ec-font-size-large);
}

.ec-text--small {
  --ec-text-font-size: var(--ec-font-size-small);
}

/* ---- Truncation ---- */
.ec-text.is-truncated {
  display: inline-block;
  max-width: 100%;
  overflow: hidden;
  white-space: nowrap;
  text-overflow: ellipsis;
}

.ec-text.is-line-clamp {
  display: -webkit-box;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: var(--ec-text-line-clamp);
  line-clamp: var(--ec-text-line-clamp);
  overflow: hidden;
  text-overflow: ellipsis;
}
